// n8n Webhook 一般输入是 { headers, params, query, body, ... }
const root = $json || {};

// 1) 拿到 body（回调内容）
const body = (root.body && typeof root.body === 'object') ? root.body : root;

// 2) 新格式：body.context；旧格式：root.query（callbackUrl 参数）
const query = (root.query && typeof root.query === 'object') ? root.query : {};
const context = (body.context && typeof body.context === 'object') ? body.context : {};

// ---------- 统一取字段 ----------
const status = String(body.status ?? body.data?.status ?? '').toLowerCase();
// 新格式成功：status=success 或 data.status=completed
const ok =
  status === 'success' ||
  status === 'completed' ||
  status === 'succeeded' ||
  String(body.data?.status ?? '').toLowerCase() === 'completed' ||
  String(body.data?.status ?? '').toLowerCase() === 'success';

// taskId：新格式 task_id / data.id；旧格式 data.taskId
const taskId =
  body.task_id ||
  body.taskId ||
  body.data?.id ||
  body.data?.taskId ||
  null;

// resultUrl：新格式 video_url / data.video_url；旧格式 resultJson 里 resultUrls[0]
let resultUrl =
  body.video_url ||
  body.data?.video_url ||
  body.data?.result_url ||
  null;

if (!resultUrl && body.data && typeof body.data.resultJson === 'string') {
  try {
    const parsed = JSON.parse(body.data.resultJson);
    if (Array.isArray(parsed.resultUrls) && parsed.resultUrls[0]) {
      resultUrl = parsed.resultUrls[0];
    }
  } catch (e) {}
}

// msg / failMsg：尽量把失败原因找出来
const failMsg =
  body.failMsg ||
  body.data?.failMsg ||
  body.error?.message ||
  body.error_message ||
  body.message ||
  body.msg ||
  '';

const msg = ok ? 'success' : (failMsg || 'failed');

// 3) 上下文：优先新格式 context，其次 query（兼容老逻辑）
const pick = (a, b) => (a != null && String(a).trim() !== '' ? a : b);

return {
  json: {
    // 保持你原有 IF 的判断方式：codeStr === "200" 即成功
    code: ok ? 200 : 500,
    codeStr: ok ? '200' : '500',
    msg,

    status: body.status ?? body.data?.status ?? null,
    taskId,
    resultUrl,
    failMsg,

    // 源记录（父表）
    record_id: pick(context.record_id, query.record_id),
    app_token: pick(context.app_token, query.app_token),
    table_id: pick(context.table_id, query.table_id),

    // 目标表（子表，可选）
    out_app_token: pick(context.out_app_token, query.out_app_token),
    out_table_id: pick(context.out_table_id, query.out_table_id),

    tenant_access_token: pick(context.tenant_access_token, query.tenant_access_token),
    api_key: pick(context.api_key, query.api_key),
    workflow_id_for_credits: pick(context.workflow_id_for_credits, query.workflow_id_for_credits),

    // 方便排查
    debug_raw_keys: Object.keys(body || {}),
  }
};

// 准备上传 OSS 的参数，所有上下文都用当前 $json
const item = $input.item;
const base = item.json;

return {
  json: {
    taskId: base.taskId,
    record_id: base.record_id,
    app_token: base.app_token,
    table_id: base.table_id,
    tenant_access_token: base.tenant_access_token,
    api_key: base.api_key,
    workflow_id_for_credits: base.workflow_id_for_credits,
    fileName: `keling_video_${base.taskId}.mp4`
  },
  // 把 HTTP 节点下载的二进制视频透传出去
  binary: item.binary
};

// OSSClient 节点输出里，name 就是对象 key，例如：n8n_data/2025-12-14/xxx.mp4
const keyRaw = $json.name || $json.objectKey || '';
const key = String(keyRaw).replace(/^\/+/, ''); // 防御：避免出现 //

// 你的自定义域名（已绑定 bucket）
const cdnHost = 'https://oss.flowonn.com';

const publicUrl = `${cdnHost}/${encodeURI(key)}`;

return {
  json: {
    publicUrl,
    record_id: $json.record_id,
    app_token: $json.app_token,
    table_id: $json.table_id,
    tenant_access_token: $json.tenant_access_token,
    api_key: $json.api_key,
    workflow_id_for_credits: $json.workflow_id_for_credits,
  }
};

return await (async () => {
  const items = $input.all();
  if (!items.length) throw new Error('没有输入数据');

  const output = [];

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const binary = item.binary || {};
    const keys = Object.keys(binary);
    if (!keys.length) throw new Error(`第 ${i} 条 item 没有任何 binary 数据`);

    const key = keys[0];
    const binData = binary[key];
    if (!binData) throw new Error(`第 ${i} 条 item 的 ${key} 不存在`);

    const fileName = binData.fileName || `nano_result_${Date.now()}_${i}.jpg`;

    // ✅ 关键：从 n8n 拿到真实文件 buffer（兼容 /tmp 落盘模式）
    let buffer;
    try {
      buffer = await this.helpers.getBinaryDataBuffer(i, key);
    } catch (e) {
      // 兜底：如果确实是 base64 内容（非落盘模式），再用 base64 解
      const raw = binData.data;
      if (!raw) throw new Error(`第 ${i} 条 item 的 ${key} 没有 data，且 getBinaryDataBuffer 失败：${e.message}`);
      const b64 = String(raw).replace(/^data:.*;base64,/, '');
      buffer = Buffer.from(b64, 'base64');
    }

    output.push({
      json: {
        fileName,
        fileSize: buffer.length, // ✅ 真实字节数
        binaryKey: key,
      },
      binary: {
        [key]: {
          ...binData,
          fileName,
        },
      },
    });
  }

  return output;
})();

/**
 * 解析飞书 drive/v1/medias/upload_all 返回（允许失败）
 * - 成功：输出 file_token
 * - 失败：file_token = null，但给出 feishu_upload_ok=false + error 信息
 */
const input = $input.first()?.json || {};

// fullResponse: true 时会有 statusCode/body
const statusCode = input.statusCode ?? input.status ?? null;
const resp = (input.body && typeof input.body === 'object') ? input.body : input;

// 飞书常见：{ code, msg, data, error }
const apiCode = resp?.code;
const apiMsg = resp?.msg || resp?.message || input.errorDescription || input.errorMessage || '';
const data = resp?.data || {};

// 尝试取 file_token
const file_token =
  data.file_token ||
  data.fileToken ||
  resp?.file_token ||
  resp?.fileToken ||
  null;

const okByToken = !!file_token;
const okByHttp = (statusCode == null) ? false : (Number(statusCode) >= 200 && Number(statusCode) < 300);

// ✅ 只要拿到 file_token 就算成功（最稳）
const feishu_upload_ok = okByToken && (okByHttp || true);

// 透传上下文（从当前 json 里拿）
const passthroughKeys = [
  'publicUrl',
  'taskId',
  'record_id',
  'app_token',
  'table_id',
  'out_app_token',
  'out_table_id',
  'tenant_access_token',
  'api_key',
  'workflow_id_for_credits',
];

const passthrough = {};
for (const k of passthroughKeys) passthrough[k] = input[k];

// 错误细节（quota exceeded 时 resp.error.log_id 有用）
const log_id = resp?.error?.log_id || resp?.error?.logId || null;

return {
  json: {
    ...passthrough,
    feishu_upload_ok,
    file_token,               // 成功有值，失败为 null
    feishu_error_code: okByToken ? null : (apiCode ?? statusCode ?? null),
    feishu_error_msg: okByToken ? '' : apiMsg,
    feishu_log_id: okByToken ? null : log_id,
  },
};

const taskId = $json.taskId || `t${Date.now()}`;
return {
  json: {
    ...$json,
    taskId,
    ff_inPath: `/tmp/${taskId}.mp4`,
    ff_outPath: `/tmp/${taskId}_drop1.mp4`,
    ff_outFileName: `keling_video_${taskId}_drop1.mp4`,
  },
  binary: $binary,
};

/**
 * n8n Code 节点：整理飞书 bitable PUT 的参数（url + headers + body）
 * - publicUrl 必填（OSS 兜底）
 * - file_token 可选（飞书云空间失败时为空也能跑完）
 * 输出：
 * {
 *   url: "...",
 *   headers: {...},
 *   body: {...}   // 给 HTTP Request 节点 JSON Body 用 ={{ $json.body }}
 * }
 */

function pickText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) {
    const first = v[0];
    if (first == null) return '';
    if (typeof first === 'string') return first;
    if (typeof first === 'object') return first.text ?? first.value ?? first.link ?? first.url ?? '';
    return String(first);
  }
  if (typeof v === 'object') return v.text ?? v.value ?? v.link ?? v.url ?? '';
  return String(v);
}

function must(v, name) {
  const s = pickText(v).trim();
  if (!s) throw new Error(`${name} 为空`);
  return s;
}

// 可选值：空就返回 null（不抛错）
function opt(v) {
  const s = pickText(v).trim();
  return s ? s : null;
}

return $input.all().map((item) => {
  const j = item.json || {};

  // ====== 1) 上下文（优先当前 item，其次解析回调节点）======
  const ctx = (() => {
    try {
      return $('解析回调+上下文').item.json || {};
    } catch (e) {
      return {};
    }
  })();

  const record_id = must(j.record_id ?? ctx.record_id, 'record_id');
  const app_token = must(j.app_token ?? ctx.app_token, 'app_token');
  const table_id  = must(j.table_id  ?? ctx.table_id,  'table_id');
  const tenant_access_token = must(j.tenant_access_token ?? ctx.tenant_access_token, 'tenant_access_token');

  // ====== 2) 你要写回的字段 ======

  // 先从本 item / ctx 里找（兼容不同字段名）
  let promptText =
    j.data?.record?.fields?.['视频提示词'] ??
    j.data?.record?.fields?.['提示词'] ??
    j.data?.record?.fields?.['脚本'] ??
    j['视频提示词'] ??
    j['提示词'] ??
    j['脚本'] ??
    ctx.data?.record?.fields?.['视频提示词'] ??
    ctx.data?.record?.fields?.['提示词'] ??
    ctx.data?.record?.fields?.['脚本'] ??
    ctx['视频提示词'] ??
    ctx['提示词'] ??
    ctx['脚本'] ??
    j.prompt ??
    null;

  // ✅ 关键兜底：优先从「读取记录」取 视频提示词，再退到 脚本
  if (!pickText(promptText).trim()) {
    try {
      promptText = $('读取记录').first().json.data.record.fields['视频提示词'];
    } catch (e) {}
  }
  if (!pickText(promptText).trim()) {
    try {
      promptText = $('读取记录').first().json.data.record.fields['脚本'];
    } catch (e) {}
  }

  promptText = pickText(promptText);

  // 链接：优先当前 item，其次网址转换节点
  let publicUrl = j.publicUrl ?? j.public_url ?? j.url ?? ctx.publicUrl ?? null;

  if (!publicUrl) {
    try {
      publicUrl = $('网址转换').first().json.publicUrl;
    } catch (e) {}
  }

  publicUrl = must(publicUrl, 'publicUrl');

  // ====== 3) 组装飞书 PUT 参数 ======
  const url =
    `https://open.feishu.cn/open-apis/bitable/v1/apps/${encodeURIComponent(app_token)}` +
    `/tables/${encodeURIComponent(table_id)}/records/${encodeURIComponent(record_id)}` +
    `?user_id_type=open_id`;

  const headers = {
    Authorization: `Bearer ${tenant_access_token}`,
    'Content-Type': 'application/json; charset=utf-8',
  };

  // 基础 fields：永远写 link + 文本字段
  const fields = {
    "复刻ID": record_id,
    "生产类型": "爆款视频复刻",

    // ✅ 兼容：你表里如果叫“提示词”或“视频提示词”，都能写到
    "提示词": promptText,

    "AI生成结果": {
      link: publicUrl,
      text: "下载视频",
    },
  };

  // file_token（可选：飞书云空间失败时可能为空）
  const file_token = opt(j.file_token ?? j.fileToken ?? ctx.file_token);

  // ✅ 只有拿到 file_token 才写附件字段，避免飞书字段校验报错
  if (file_token) {
    fields["AI视频"] = [{ file_token }];
  }

  const body = { fields };

  return { json: { url, headers, body } };
});

// 安全删除：只允许删 /tmp 下的 mp4，避免误删
function safeTmpMp4(p, name) {
  if (!p) return null;
  if (typeof p !== 'string') throw new Error(`${name} 不是字符串`);
  if (!p.startsWith('/tmp/')) throw new Error(`${name} 非 /tmp 路径，拒绝删除：${p}`);
  if (!p.endsWith('.mp4')) throw new Error(`${name} 非 mp4，拒绝删除：${p}`);
  if (p.includes('..')) throw new Error(`${name} 包含 ..，拒绝删除：${p}`);
  return p;
}

const inPath = safeTmpMp4($json.ff_inPath, 'ff_inPath');
const outPath = safeTmpMp4($json.ff_outPath, 'ff_outPath');

const paths = [inPath, outPath].filter(Boolean);

// 做好引号转义
const quoted = paths.map(p => `"${p.replace(/"/g, '\\"')}"`).join(' ');

// rm -f 即使不存在也不报错；|| true 防止影响主链路
const cleanup_cmd = paths.length
  ? `rm -f ${quoted} || true`
  : `echo "no tmp files to delete"`;

return {
  json: {
    ...$json,
    cleanup_cmd,
    cleanup_paths: paths,
  },
  // 透传二进制，别把视频 binary 弄丢
  binary: $binary,
};
